mapper.select:
SELECT id, eq_code, eq_name, eq_type, status, last_pm_at
FROM equipment
WHERE id = #{id}

SELECT id, eq_code, eq_name, eq_type, status, last_pm_at
FROM equipment
WHERE eq_code = #{eqCode}

SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM equipment
WHERE eq_code = #{eqCode}

    AND id != #{excludeId}

SELECT l.id, l.equipment_id, l.log_type, l.description, l.occurred_at, l.reported_by, u.name AS reported_by_name FROM equipment_logs l LEFT JOIN users u ON u.id = l.reported_by
WHERE l.equipment_id = #{equipmentId}
ORDER BY l.occurred_at DESC

SELECT id, work_order_id, param_name, target_value, actual_value, unit, upper_limit, lower_limit, measured_at FROM process_params
WHERE work_order_id = #{workOrderId}
ORDER BY measured_at DESC
